 /// Optimize fabs(X) compared with zero.
+/// Match select patterns that compute fabs(x) but without using the fabs intrinsic.
+/// Matches patterns like: (X >= 0) ? X : -X or (X < 0) ? -X : X
+static bool matchFabsSelect(Value *V, Value *&X) {
+  SelectInst *SI = dyn_cast<SelectInst>(V);
+  if (!SI)
+    return false;
+
+  Value *Cond = SI->getCondition();
+  Value *TrueVal = SI->getTrueValue();
+  Value *FalseVal = SI->getFalseValue();
+
+  CmpInst::Predicate Pred;
+  // Match condition: fcmp (geq|ogt|ole|olt) X, 0
+  if (!match(Cond, m_FCmp(Pred, m_Value(X), m_AnyZeroFP())))
+    return false;
+
+  // Check if one arm is X and the other is -X
+  if (!match(TrueVal, m_FNeg(m_Specific(X)))) {
+    if (!match(FalseVal, m_FNeg(m_Specific(X))))
+      return false;
+    // Check: (X >= 0) ? X : -X  or  (X > 0) ? X : -X
+    // These compute fabs(X) and return X when condition is true
+    if (Pred != FCmpInst::FCMP_OGE && Pred != FCmpInst::FCMP_UGE &&
+        Pred != FCmpInst::FCMP_OGT && Pred != FCmpInst::FCMP_UGT)
+      return false;
+  } else {
+    // Check: (X < 0) ? -X : X  or  (X <= 0) ? -X : X
+    // These compute fabs(X) and return -X when condition is true
+    if (Pred != FCmpInst::FCMP_OLT && Pred != FCmpInst::FCMP_ULT &&
+        Pred != FCmpInst::FCMP_OLE && Pred != FCmpInst::FCMP_ULE)
+      return false;
+  }
+
+  return true;
+}
+
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
-    return nullptr;
+  if (!match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // Try to match select-based fabs pattern
+    if (!matchFabsSelect(I.getOperand(0), X))
+      return nullptr;
+  }

   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))

